### 2. 创建 `app/disk/components/AstrologyAnalyzer.tsx`

```typescript
'use client';

import { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
  CalendarIcon,
  ClockIcon,
  MapPinIcon,
  UserIcon,
  DocumentArrowDownIcon,
  SparklesIcon,
  CheckCircleIcon,
  ExclamationCircleIcon
} from '@heroicons/react/24/outline';
import { analyzeAstrology } from '@/services/astrology.service';
import { AstrologyForm, AstrologyResult, ExportFormat } from '@/types/astrology';
import toast, { Toaster } from 'react-hot-toast';
import LoadingSpinner from '@/components/common/LoadingSpinner';
import jsPDF from 'jspdf';
import html2canvas from 'html2canvas';

export default function AstrologyAnalyzer() {
  const [formData, setFormData] = useState<AstrologyForm>({
    name: '',
    gender: 'male',
    birthDate: '',
    birthTime: '',
    birthPlace: '',
    calendar: 'solar',
    email: ''
  });

  const [result, setResult] = useState<AstrologyResult | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [showResult, setShowResult] = useState(false);
  const [exportFormat, setExportFormat] = useState<ExportFormat>('pdf');

  // 处理表单提交
  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    // 验证表单
    if (!validateForm()) {
      return;
    }

    setIsAnalyzing(true);

    try {
      // 调用 API 进行分析
      const response = await analyzeAstrology(formData);

      setResult(response);
      setShowResult(true);
      toast.success('命书生成成功！');
    } catch (error: any) {
      console.error('Analysis error:', error);
      toast.error(error.message || '分析失败，请稍后重试');
    } finally {
      setIsAnalyzing(false);
    }
  };

  // 表单验证
  const validateForm = (): boolean => {
    if (!formData.name) {
      toast.error('请输入姓名');
      return false;
    }
    if (!formData.birthDate) {
      toast.error('请选择出生日期');
      return false;
    }
    if (!formData.birthTime) {
      toast.error('请选择出生时间');
      return false;
    }
    if (!formData.birthPlace) {
      toast.error('请输入出生地点');
      return false;
    }
    return true;
  };

  // 导出命书
  const handleExport = async (format: ExportFormat) => {
    if (!result) return;

    const loadingToast = toast.loading(`正在导出 ${format.toUpperCase()} 文件...`);

    try {
      switch (format) {
        case 'pdf':
          await exportToPDF();
          break;
        case 'word':
          await exportToWord();
          break;
        case 'excel':
          await exportToExcel();
          break;
        default:
          throw new Error('不支持的导出格式');
      }

      toast.success('导出成功！', { id: loadingToast });
    } catch (error) {
      toast.error('导出失败，请重试', { id: loadingToast });
      console.error('Export error:', error);
    }
  };

  // 导出为 PDF
  const exportToPDF = async () => {
    const element = document.getElementById('astrology-result');
    if (!element) return;

    const canvas = await html2canvas(element, {
      scale: 2,
      useCORS: true,
      logging: false
    });

    const imgData = canvas.toDataURL('image/png');
    const pdf = new jsPDF('p', 'mm', 'a4');
    const imgWidth = 210;
    const pageHeight = 297;
    const imgHeight = (canvas.height * imgWidth) / canvas.width;
    let heightLeft = imgHeight;

    let position = 0;

    pdf.addImage(imgData, 'PNG', 0, position, imgWidth, imgHeight);
    heightLeft -= pageHeight;

    while (heightLeft >= 0) {
      position = heightLeft - imgHeight;
      pdf.addPage();
      pdf.addImage(imgData, 'PNG', 0, position, imgWidth, imgHeight);
      heightLeft -= pageHeight;
    }

    pdf.save(`${formData.name}_命书_${new Date().toISOString().split('T')[0]}.pdf`);
  };

  // 导出为 Word (简化版，实际需要后端支持)
  const exportToWord = async () => {
    // 这里需要后端 API 支持生成 Word 文档
    const response = await fetch('/api/astrology/export/word', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ result, formData })
    });

    if (response.ok) {
      const blob = await response.blob();
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `${formData.name}_命书_${new Date().toISOString().split('T')[0]}.docx`;
      a.click();
    }
  };

  // 导出为 Excel (简化版)
  const exportToExcel = async () => {
